var gis = vars.gisResponse.Envelope.Body.getAddressDetailsV1x0ResponseElement.tservresultOut
var addr = gis.addressinfo
var billingList =
    if (isEmpty(gis.billingaddresslist)) [] 
    else  gis.billingaddresslist.*array 
var commercialAddress = billingList filter ($.addrtype == "C")   
var gisstatuscode = gis.gisstatuscode default ""
var gisstatusmsg = gis.gisstatuscode default ""

---
if (gisstatuscode == "ERROR") 
    { 
        stop: true, 
        message: gisstatusmsg 
    }
else if (isEmpty(addr.gisuspsdpvconfcode)) 
    { 
        stop: true, 
        message: p('gis.validation.addrNotFoundMsg')
    }
else if ((gis.servrecommendation.gisrecommendationcolor default "") != "GREEN") 
    { 
        stop: true, 
        message: p('gis.validation.gisServiceabilityIndicatorMsg')
                 ++ (gis.servrecommendation.gisrecommendationcolor default "Unknown") 
    }
else if (addr.gisuspsdpvconfcode == "D") 
    { 
        stop: true, 
        message: p('gis.validation.gisuspsdpvconfcodeTypeD')
    }
else if (addr.gisuspsdpvconfcode == "S") 
    { 
        stop: true, 
        message: p('gis.validation.gisuspsdpvconfcodeTypeS')
    }
else if (sizeOf(commercialAddress) > 1) 
    { 
        stop: true, 
        message:  p('gis.validation.multipleCommercialHk')  
    }
else if (addr.gisuspsdpvconfcode == "N") 
    { 
        stop: true, 
        message: p('gis.validation.gisuspsdpvconfcodeTypeN')
    }
else if (addr.gisuspsdpvconfcode == "U") 
    { 
        stop: true, 
        message: p('gis.validation.gisuspsdpvconfcodeTypeU')
    }
else if( ((commercialAddress[0].billeraddr) scan 
	p('gis.validation.unitMatchPattern') map ($[1]) joinBy ""
) != vars.customSfPayload.unit) 
    { 
        stop: false, 
        message: "follow_clonning_path"
    }
else 
    { 
        stop: false, 
        message: p('gis.validation.gisValidationSucessMsg')
    }

