output application/java

// STEP 1 — Build the match key
// If you later have occurrence on BOTH sides, append it to this key.
fun k(r) =
  (r.Service_Code__c as String)
  ++ "|" ++ (r.Service_Quantity__c as String)
  ++ "|" ++ (r.Service_Rate__c as String)

// STEP 2 — Group OLIs by key so we can access the i-th OLI for a key
var oliByKey = (vars.sfOliResponse default []) groupBy ((o) -> k(o))

// STEP 3 — Tag SPC rows with their original position to restore order later
var spcWithPos = (vars.spcBssOnlyRecords default []) map ((row, i) -> row ++ { rkPos: i })

// STEP 4 — Group SPC by key (so we can pair SPC[i] with OLI[i] inside each key)
var spcByKey = spcWithPos groupBy ((row) -> k(row))

// STEP 5 — For each key bucket, enrich SPC[i] with OLI[i] (if it exists)
// This guarantees 1:1, in-order pairing and prevents reuse.
var enrichedBuckets =
  spcByKey pluck ((spcs, key) -> do {
    var olis = oliByKey[key] default []
    ---
    spcs map ((s, i) ->
      s ++ (
        if (sizeOf(olis) > i)
          {
            Opportunity_Line_Item__c:      olis[i].Opportunity_Line_Item__c,
            EnterpriseQuoteLineItemId__c:  olis[i].EnterpriseQuoteLineItemId__c,
            Service_Request_Id__c:			olis[i].Service_Request__c,
            Future_Bill_Date__c:           olis[i].Future_Bill_Date__c,
            Service_Active_Date__c:        olis[i].Service_Active_Date__c,
            Actual_Install_Date__c:        olis[i].Actual_Install_Date__c
          }
        else {}
      )
    )
  })

// STEP 6 — Flatten buckets, restore original SPC order, and drop helper field
var flattened = flatten(enrichedBuckets default [])
var ordered   = orderBy(flattened, (x) -> x.rkPos)

---
ordered map ($ - "rkPos")

