%dw 2.0
import * from dw::core::Strings
import * from dw::util::Values
output application/json
var oldIssues = if(vars.kafkaPayload.issues != null and ((p('issues.capabilities') splitBy ",") contains  vars.kafkaPayload.issues[0].'type'))((payload[0][p("issues." ++ (lower(vars.kafkaPayload.issues[0].'type')default "") replace /([\-\, "&", " "])/with"_")] default ";") splitBy  ";") else null
var oldcreateddate = if(vars.kafkaPayload.issues != null and vars.kafkaPayload.issues[0].'type' != "Request ISP Design" and vars.kafkaPayload.issues[0].'type' != "SECD Validation and System Update" and ((p('issues.capabilities') splitBy ",") contains  vars.kafkaPayload.issues[0].'type')) ((payload[0][p("issues." ++ ((lower(vars.kafkaPayload.issues[0].'type')default "" ++ "_createddate") replace /([\-\, "&", " "])/with"_"))] ) ) else null
var newIssues = if(vars.kafkaPayload.issues != null)((vars.kafkaPayload.issues[0].statusReason) splitBy  ";") else null
var newcreateddate = (vars.kafkaPayload.issues[0].createdTimestamp)
var filteredIssues = {

      "pxObjClass": vars.kafkaPayload.issues[0].pxObjClass,

      "statusReason": if(newIssues != null and oldIssues != null and (vars.kafkaPayload.issues[0].statusReason) != "null" )(oldIssues  default [] ++ ((oldIssues default [] ++ newIssues default [])-- oldIssues  default []) joinBy  ";")  
	  else if( (vars.kafkaPayload.issues[0].statusReason) != null) (vars.kafkaPayload.issues[0].statusReason) 
	  else null,

      "resolvedTimestamp": if(vars.kafkaPayload.issues[0].resolvedTimestamp == null or vars.kafkaPayload.issues[0].resolvedTimestamp == "null")(" ") else (vars.kafkaPayload.issues[0].resolvedTimestamp),

      "createdTimestamp": if(isEmpty(oldcreateddate) )(newcreateddate) else if(newcreateddate != null and  newcreateddate != "null" and (oldcreateddate as Date as String{format : "MM-dd-yyyy"} as Date{format : "MM-dd-yyyy"}) <
(newcreateddate as Date{format : "MM-dd-yyyy"} )) (oldcreateddate  as Date as String{format : "MM-dd-yyyy"}
)
    else(newcreateddate) ,


      "type": vars.kafkaPayload.issues[0]."type",

      "group": vars.kafkaPayload.issues[0].group,

      "pxUpdateDateTime": vars.kafkaPayload.issues[0].pxUpdateDateTime

}
---

vars.kafkaPayload  update "issues" with [filteredIssues]

