    MAC00073 : ({
        INL01520 :  flatten(((flatten([payload.ICOMS.MAC00073.*INL01520 default []] ++ [payload.ICOMS.MAC00073.*INL00783 default []]) map ((item, index) -> {
          SRVCCTGRYCODE : if(!isEmpty(item.@SRVCCTGRYCODE)) (item.@SRVCCTGRYCODE) 
          				  else if(!isEmpty(vars.mac100Response filter ($.SERVICE_CODE == item.@FORCOCRNCSRVC) map ((item3, index3) -> item3.SRVCCTGRYCODE3)joinBy "")) 
				          		(vars.mac100Response filter ($.SERVICE_CODE == item.@FORCOCRNCSRVC) map ((item3, index3) -> item3.SRVCCTGRYCODE3)joinBy "")
						  else (vars.OLI_MRC_MAP filter ((item4, index) -> item.@FORCOCRNCSRVC == item4.Ntl_ICOMS_Service_Code__c))[0].ServiceCategoryCode,
          SRVCOCRNC : item.@SRVCOCRNC,
          SRVCCODE: item.@SRVCCODE default item.@FORCOCRNCSRVC,
          SRVCRATE: item.@SRVCRATE,
          SRVCQNTY: item.@SRVCQNTY,
          CSTMRSRVCBILLDSCRPTN: item.@CSTMRSRVCBILLDSCRPTN,
          ALLWRATEOVRD: item.@ALLWRATEOVRD,
          CSTBLLDSCOVRD: item.@CSTBLLDSCOVRD,
          FNCTNRTRNCODE: item.@FNCTNRTRNCODE,
          IGIMESSTXT: item.@IGIMESSTXT,
          ADTNLOCCQTY: item.@ADTNLOCCQTY,
          EXTRNLOFFRID: item.@EXTRNLOFFRID
        })) groupBy ((value, key) -> value.SRVCCODE ) pluck $ map (item, index) -> {
            ((item map ((item2, index) -> abc : item2 ++ {"sequence" : index + 1})))
        }) map (item) -> 
        (item pluck ((value, key) -> value))) 
    }) 
}

